const post = $json;
const content = post.content?.raw || post.content?.rendered || '';
const title = post.title?.raw || post.title?.rendered || '';

if (!content || content.length < 50) {
  return { json: { process: false, id: post.id, title: title, reason: 'Empty content' } };
}

return { json: { process: true, id: post.id, title: title, content: content } };

const prepData = $items('IF Process')[$itemIndex]?.json || {};
const response = $json;

try {
  let text = response.choices?.[0]?.message?.content || '';
  text = text.replace(/^```json\s*/i, '').replace(/```$/i, '').trim();

  const first = text.indexOf('{');
  const last = text.lastIndexOf('}');
  if (first === -1 || last === -1) throw new Error('No JSON');

  const result = JSON.parse(text.slice(first, last + 1));

  if (!result.fixed_content) {
    return { json: { update: false, id: prepData.id, title: prepData.title, reason: 'No fixed_content' } };
  }

  return { json: { update: true, id: prepData.id, title: prepData.title, fixed_content: result.fixed_content, changes: result.changes_made || 0 } };
} catch (e) {
  return { json: { update: false, id: prepData.id, title: prepData.title, reason: 'Parse error: ' + e.message } };
}

const wpResult = $json;
const parseData = $items('IF Update')[$itemIndex]?.json || {};

return { json: { status: 'SUCCESS', id: parseData.id, title: parseData.title, changes: parseData.changes, wp_modified: wpResult.modified } };
